def generate_candidates(existing: set[str], rng: random.Random) -> list[Candidate]:
    out: list[Candidate] = []
    onames = [o for o, _, _, _ in ORGANS]

    for organ, func, wrong, diff in ORGANS:
        pool = wrong + [func]
        _add(out, existing, rng, f"'{organ}'-ന്റെ പ്രധാന പ്രവർത്തനം എന്താണ്?", func, pool, diff)
        _add(out, existing, rng, f"'{func}' ഏത് അവയവത്തിന്റെ പ്രവർത്തനമാണ്?", organ, onames, diff)

    for org, func, wrong, diff in ORGANELLES:
        pool = wrong + [func]
        on = [o for o, _, _, _ in ORGANELLES]
        _add(out, existing, rng, f"കോശത്തിലെ '{org}'-ന്റെ പ്രധാന പ്രവർത്തനം?", func, pool, diff)
        _add(out, existing, rng, f"'{func}' ഏത് കോശാവയവത്തിന്റെ പ്രവർത്തനമാണ്?", org, on, diff)

    for vit, func, wrong, diff in VITAMINS:
        pool = wrong + [func]
        vnames = [v for v, _, _, _ in VITAMINS]
        _add(out, existing, rng, f"വിറ്റാമിൻ '{vit}'-ന്റെ പ്രധാന പ്രവർത്തനം?", func, pool, diff)
        _add(out, existing, rng, f"'{func}' ഏത് വിറ്റാമിന്റെ പ്രവർത്തനമാണ്?", vit, vnames, diff)

    for dis, agent, wrong, diff in DISEASES:
        pool = wrong + [agent]
        dnames = [d for d, _, _, _ in DISEASES]
        _add(out, existing, rng, f"'{dis}'-ന് കാരണമായ കീടാണു/ജീവി?", agent, pool, diff)
        _add(out, existing, rng, f"'{agent}' ഏത് രോഗത്തിന് കാരണമാകുന്നു?", dis, dnames, diff)

    for topic, person, wrong, diff in SCIENTISTS:
        pool = wrong + [person]
        disc = [t for t, _, _, _ in SCIENTISTS]
        pers = [p for _, p, _, _ in SCIENTISTS]
        _add(out, existing, rng, f"'{topic}'-ന് ബന്ധപ്പെട്ട ജീവശാസ്ത്രജ്ഞൻ?", person, pool, diff)
        _add(out, existing, rng, f"'{person}'-ന്റെ പ്രധാന സംഭാവന?", topic, disc, diff)
        _add(out, existing, rng, f"ജീവശാസ്ത്രത്തിൽ '{person}' ആരാണ്?", person, pers, diff)

    for q, ans, wrong, diff in TAXONOMY:
        pool = wrong + [ans]
        _add(out, existing, rng, f"ജീവവർഗ്ഗീകരണത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in PLANTS:
        pool = wrong + [ans]
        pnames = [p[0] for p in PLANTS]
        _add(out, existing, rng, f"'{q}'-ന്റെ ശാസ്ത്രീയ/പ്രധാന പേര്?", ans, pool, diff)
        _add(out, existing, rng, f"'{ans}' ഏത് സസ്യവുമായി ബന്ധപ്പെട്ടത്?", q, pnames, diff)

    for q, ans, wrong, diff in ANIMALS:
        pool = wrong + [ans]
        anames = [a[0] for a in ANIMALS]
        _add(out, existing, rng, f"'{q}'-ന്റെ ശാസ്ത്രീയ/പ്രധാന പേര്?", ans, pool, diff)
        _add(out, existing, rng, f"'{ans}' ഏത് ജീവിയുമായി ബന്ധപ്പെട്ടത്?", q, anames, diff)

    for q, ans, wrong, diff in CELL:
        pool = wrong + [ans]
        _add(out, existing, rng, f"കോശജീവശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)
        _add(out, existing, rng, f"'{ans}' ഏതിനെ സൂചിപ്പിക്കുന്നു?", q, [c[0] for c in CELL], diff)

    for h, func, wrong, diff in HORMONES:
        pool = wrong + [func]
        hnames = [x for x, _, _, _ in HORMONES]
        _add(out, existing, rng, f"ഹോർമോൺ '{h}'-ന്റെ പ്രധാന പ്രവർത്തനം?", func, pool, diff)
        _add(out, existing, rng, f"'{func}' ഏത് ഹോർമോണിന്റെ പ്രവർത്തനമാണ്?", h, hnames, diff)

    for m, func, wrong, diff in MINERALS:
        pool = wrong + [func]
        mnames = [x for x, _, _, _ in MINERALS]
        _add(out, existing, rng, f"'{m}' ധാതുവിന്റെ പ്രധാന പ്രവർത്തനം?", func, pool, diff)
        _add(out, existing, rng, f"'{func}' ഏത് ധാതുവിന്റെ പ്രവർത്തനമാണ്?", m, mnames, diff)

    for enz, func, wrong, diff in ENZYMES:
        pool = wrong + [func]
        enames = [e for e, _, _, _ in ENZYMES]
        _add(out, existing, rng, f"എൻസൈം '{enz}'-ന്റെ പ്രവർത്തനം?", func, pool, diff)
        _add(out, existing, rng, f"'{func}' ഏത് എൻസൈമിന്റെ പ്രവർത്തനമാണ്?", enz, enames, diff)

    for q, ans, wrong, diff in BLOOD:
        pool = wrong + [ans]
        _add(out, existing, rng, f"രക്തശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in GENETICS:
        pool = wrong + [ans]
        _add(out, existing, rng, f"ജനിതകശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in ECOLOGY:
        pool = wrong + [ans]
        _add(out, existing, rng, f"പാരിസ്ഥിതികശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in NUTRITION:
        pool = wrong + [ans]
        _add(out, existing, rng, f"പോഷകശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in REPRODUCTION:
        pool = wrong + [ans]
        _add(out, existing, rng, f"പ്രജനനശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in IMMUNITY:
        pool = wrong + [ans]
        _add(out, existing, rng, f"രോഗപ്രതിരോധശാസ്ത്രത്തിൽ '{q}'?", ans, pool, diff)


    for n in range(2, 50):
        for m in range(2, 30):
            total = 2 * n + 2 * m
            wrong = [str(total + k) for k in (1, 2, n, m) if total + k != total][:3]
            _add(out, existing, rng,
                f"diploid: n={n}, m={m} — ആകെ ക്രോമോസോം എണ്ണം?",
                str(total), wrong, "hard")

    for bp in range(100, 5000, 100):
        for gc in range(30, 70, 5):
            ans = str(bp * gc // 100)
            wrong = [str(int(ans) + k) for k in (bp // 10, gc, 10) if int(ans) + k != int(ans)][:3]
            _add(out, existing, rng,
                f"DNA {bp} bp, GC {gc}% — GC bp എണ്ണം?",
                ans, wrong, "hard")


    for q, ans, wrong, diff in BIO_EXTRA:
        pool = wrong + [ans]
        _add(out, existing, rng, q, ans, pool, diff)


    for q, ans, wrong, diff in BIO_EXTRA_2:
        pool = wrong + [ans]
        _add(out, existing, rng, q, ans, pool, diff)


    for q, ans, wrong, diff in BIO_EXTRA_3:
        pool = wrong + [ans]
        _add(out, existing, rng, q, ans, pool, diff)

    return out
